module top_module(
    input CLK,
    input reset,
    output reg CLK_div
);reg [3:0] obf_counter;

    always @ (posedge CLK or posedge reset) begin
        if (reset) begin
            obf_counter <= 0;
            CLK_div <= 0;
        end
        else begin
            obf_counter <= obf_counter + 1;
            if (obf_counter == 4) begin
                obf_counter <= 0;
                CLK_div <= ~CLK_div;
            end
        end
    end

endmodule
